#include <ESP8266WiFi.h>
#include <AsyncMqttClient.h>
#include <SimpleTimer.h>

#define LED_PIN 2

AsyncMqttClient mqttClient;
SimpleTimer keepAliveTimer;
bool enabledWaterPump = false;
int keepAliveCount = 0;
const char *toggleWaterTopic = "toggle/water";
const char *onOffWaterTopic = "on_off/water";
const char *keepAliveTopic = "keep/alive";
const char *mqttServer = "192.168.200.70";
const uint16_t mqttPort = 1883;

// O water-control/server espera payloads no formato secretKey:iam[:type:value].
// Troque CHANGE_ME_SECRET_KEY pelo SECRET_KEY do servidor antes de usar com o broker real.
const char *keepAlivePayload = "CHANGE_ME_SECRET_KEY:asker";
const char *manualOnPayload = "CHANGE_ME_SECRET_KEY:asker:manual:1";
const char *manualOffPayload = "CHANGE_ME_SECRET_KEY:asker:manual:0";

void onLed()
{
    digitalWrite(LED_PIN, LOW);
}

void offLed()
{
    digitalWrite(LED_PIN, HIGH);
}

void publishStatus(const char *source)
{
    if (enabledWaterPump) {
        mqttClient.publish(onOffWaterTopic, 0, false, manualOnPayload);
        Serial.println("MQTT publish on_off/water manual:1");
    } else {
        mqttClient.publish(onOffWaterTopic, 0, false, manualOffPayload);
        Serial.println("MQTT publish on_off/water manual:0");
    }
}

void publishKeepAlive()
{
    if (mqttClient.connected()) {
        keepAliveCount++;
        mqttClient.publish(keepAliveTopic, 0, false, keepAlivePayload);
        Serial.print("MQTT keepalive #");
        Serial.println(keepAliveCount);
    }
}

void onMqttConnect(bool sessionPresent)
{
    Serial.println("MQTT On!");
    onLed();
    mqttClient.subscribe(toggleWaterTopic, 0);
    publishKeepAlive();
}

void onMqttDisconnect(AsyncMqttClientDisconnectReason reason)
{
    Serial.println("MQTT Off!");
    offLed();
}

void onMqttMessage(char *topic, char *payload, AsyncMqttClientMessageProperties properties, size_t len, size_t index, size_t total)
{
    Serial.print("MQTT RX ");
    Serial.print(topic);
    Serial.print(" ");

    for (size_t i = 0; i < len; i++) {
        Serial.write(payload[i]);
    }

    Serial.println();

    if (topic[0] == 't' && payload[0] == '1') {
        enabledWaterPump = true;
        publishStatus("mqtt");
    }
}

void setup()
{
    Serial.begin(9600);
    pinMode(LED_PIN, OUTPUT);
    offLed();

    WiFi.mode(WIFI_STA);
    WiFi.begin("VirtualLab", "secret");

    if (WiFi.status() == WL_CONNECTED && WiFi.internetAvailable()) {
        Serial.println("Wi-Fi connected with internet");
    }

    mqttClient.onConnect(onMqttConnect);
    mqttClient.onDisconnect(onMqttDisconnect);
    mqttClient.onMessage(onMqttMessage);
    mqttClient.setServer(mqttServer, mqttPort);
    keepAliveTimer.setInterval(8300, publishKeepAlive);
    mqttClient.connect();
}

void loop()
{
    keepAliveTimer.run();
    delay(1000);
}
